// Find the most recent planilla-salarial URL from the index page
const html = $input.first().json.data || '';

const MESES = {
  enero: '01', febrero: '02', marzo: '03', abril: '04',
  mayo: '05', junio: '06', julio: '07', agosto: '08',
  septiembre: '09', setiembre: '09', octubre: '10',
  noviembre: '11', diciembre: '12'
};

const matches = [
  ...html.matchAll(/href=["'](https?:\/\/suterh\.org\.ar\/planilla-salarial-([a-z]+)-(\d{4})\/?)["']/gi)
];

if (matches.length === 0) {
  throw new Error('No se encontraron links de planillas en el índice SUTERH');
}

const parsed = matches
  .map(m => ({
    url: m[1].endsWith('/') ? m[1] : m[1] + '/',
    mesKey: m[2].toLowerCase(),
    anio: parseInt(m[3], 10)
  }))
  .filter(p => MESES[p.mesKey])
  .map(p => ({ ...p, monthNum: parseInt(MESES[p.mesKey], 10) }))
  .sort((a, b) => b.anio - a.anio || b.monthNum - a.monthNum);

if (parsed.length === 0) {
  throw new Error('No se pudo parsear ningun link de planilla');
}

const best = parsed[0];
const mes = String(best.monthNum).padStart(2, '0');
const periodo = `${best.anio}-${mes}-01`;

return [{ json: { planillaUrl: best.url, periodo } }];

const html = $input.first().json.data || '';
const { periodo, planillaUrl: fuente } = $('Extraer URL del Mes').first().json;

const extractNumber = (text) => {
  // Spanish format: 1.089.785 (dots=thousands, comma=decimal)
  const clean = String(text).replace(/\./g, '').replace(',', '.');
  const n = parseFloat(clean);
  return isNaN(n) ? 0 : n;
};

const stripTags = (s) => s.replace(/<[^>]+>/g, '').replace(/&nbsp;/gi, ' ').trim();

const escalas = [];
const adicionales = [];

const rows = [...html.matchAll(/<tr[\s\S]*?<\/tr>/gi)];

for (const rowMatch of rows) {
  const cells = [...rowMatch[0].matchAll(/<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi)]
    .map(m => stripTags(m[1]));

  if (cells.length < 2) continue;

  const label = cells[0];
  if (!label || /funci.n|concepto|categor.a|header/i.test(label)) continue;

  const nums = cells.slice(1).map(extractNumber);
  const positiveNums = nums.filter(n => n > 100);

  if (positiveNums.length >= 4) {
    escalas.push({
      periodo,
      funcion: label,
      cat_1: positiveNums[0],
      cat_2: positiveNums[1],
      cat_3: positiveNums[2],
      cat_4: positiveNums[3],
      fuente_url: fuente
    });
  } else if (positiveNums.length === 1) {
    adicionales.push({
      periodo,
      concepto: label,
      valor: positiveNums[0],
      fuente_url: fuente
    });
  }
}

if (escalas.length === 0) {
  throw new Error(`No se encontraron escalas en ${fuente}. Verificar estructura HTML.`);
}

return [{ json: { escalas, adicionales, periodo, fuente, totalEscalas: escalas.length, totalAdicionales: adicionales.length } }];
